class UsageError(Exception):
    pass


_OPTIONS = {
    "--mode": {"dest": "mode", "env": "APP_MODE", "default": "fast"},
    "--preset": {"dest": "preset", "env": "APP_PRESET", "default": "balanced"},
}


def help_text():
    return (
        "Usage: prog [--mode MODE | --preset PRESET]\n"
        "\n"
        "Options:\n"
        "  --mode MODE       Set the mode (env: APP_MODE, default: fast)\n"
        "  --preset PRESET   Set the preset (env: APP_PRESET, default: balanced)\n"
        "\n"
        "--mode and --preset are mutually exclusive; at most one may be supplied.\n"
    )


def resolve(argv, env):
    cli_values = {}

    i = 0
    while i < len(argv):
        token = argv[i]

        if not token.startswith("--"):
            raise UsageError(f"unexpected argument: {token}")

        if "=" in token:
            key, value = token.split("=", 1)
        else:
            key = token
            if key not in _OPTIONS:
                raise UsageError(f"unknown option: {key}")
            if i + 1 >= len(argv):
                raise UsageError(f"option {key} requires a value")
            value = argv[i + 1]
            i += 1

        if key not in _OPTIONS:
            raise UsageError(f"unknown option: {key}")

        cli_values[_OPTIONS[key]["dest"]] = value
        i += 1

    env_values = {}
    for opt in _OPTIONS.values():
        if opt["env"] in env:
            env_values[opt["dest"]] = env[opt["env"]]

    supplied = {
        opt["dest"]: (opt["dest"] in cli_values or opt["dest"] in env_values)
        for opt in _OPTIONS.values()
    }

    if all(supplied.values()):
        raise UsageError("--mode and --preset are mutually exclusive; only one may be supplied")

    result = {}
    for opt in _OPTIONS.values():
        dest = opt["dest"]
        if dest in cli_values:
            result[dest] = cli_values[dest]
        elif dest in env_values:
            result[dest] = env_values[dest]
        else:
            result[dest] = opt["default"]

    return result

